import pyotp
import qrcode

# Generate TOTP secret for user
user_secret = pyotp.random_base32()

# Create QR code for authenticator app
totp_uri = pyotp.totp.TOTP(user_secret).provisioning_uri("user@domain.com", issuer_name="YourApp")
qr = qrcode.QRCode(version=1, error_correction=qrcode.constants.ERROR_CORRECT_L, box_size=10, border=4)
qr.add_data(totp_uri)
qr.make(fit=True)
qr_img = qr.make_image(fill_color="black", back_color="white")
qr_img.save('qr_code.png')

# Validate TOTP codes
def validate_totp(user_secret, totp_code):
    totp = pyotp.TOTP(user_secret)
    return totp.verify(totp_code)

# Example usage
input_totp_code = input("Enter TOTP code: ")
if validate_totp(user_secret, input_totp_code):
    print("TOTP code is valid.")
else:
    print("TOTP code is invalid.")